import React, { useEffect } from "react";
import CustomInput from "../../components/CustomInput";
import ReactQuill from "react-quill";
import { useLocation, useNavigate } from "react-router-dom";
import "react-quill/dist/quill.snow.css";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { useDispatch, useSelector } from "react-redux";
import { AiOutlineUpload } from "react-icons/ai";
import Dropzone from "react-dropzone";
import { createDocuments, resetState } from "../../features/Document/DocumentSlice";
import { delImg, uploadImg } from "../../features/upload/uploadSlice";

// Validation schema
let schema = yup.object().shape({
  TinNumber: yup.string().required("Tin Number is Required"),
});

const AddDocument = () => {
  const dispatch = useDispatch();
  //const location = useLocation();
  //const navigate = useNavigate();

  const newDocument = useSelector((state) => state.document);

  const { isSuccess, isError, isLoading, createdDocument } = newDocument;

  useEffect(() => {
    dispatch(resetState());
  }, [dispatch]);

  useEffect(() => {
    if (isSuccess && createdDocument) {
      toast.success("Document Added Successfully!");
      
      window.location.reload();
    }

    if (isError) {
      toast.error("Something Went Wrong!");
    }
  }, [isSuccess, isError, createdDocument]);

  const formik = useFormik({
    initialValues: {
      TinNumber: "",
      images: [],
      idCardImages: [],
      PostedByuserId:"",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      dispatch(createDocuments(values));
      formik.resetForm();
      setTimeout(() => {
        dispatch(resetState());
      }, 3000);
    },
  });

  const handleImageUpload = (files, field) => {
  
  
    
    dispatch(uploadImg(files)).then((uploadedImages) => {
      formik.setFieldValue(field, [
        ...(formik.values[field] || []),
        ...uploadedImages.payload,
      ]);
    });
  };

  const handleImageDelete = async (id, field) => {
    try {
      const response = await dispatch(delImg(id));
      if (response.payload && response.payload.success) {
        formik.setFieldValue(
          field,
          formik.values[field].filter((img) => img.public_id !== id)
        );
        toast.success("Image deleted successfully!");
      } else {
        throw new Error("Failed to delete image");
      }
    } catch (err) {
      toast.error("Error deleting image");
      console.error("Error deleting image:", err);
    }
  };
  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));
    if (user) {
      formik.setFieldValue("PostedByuserId", user._id || "");
    }
  }, []);
  return (
    <div>
      <h3 className="mb-4 title">Upload Documents</h3>
      <div>
        <form onSubmit={formik.handleSubmit} className="d-flex gap-3 flex-column">
          {/* Tin Number Input */}
          <CustomInput
            type="text"
            className="py-2 mb-1"
            label="Enter Tin Number"
            name="TinNumber"
            onChng={formik.handleChange("TinNumber")}
            onBlr={formik.handleBlur("TinNumber")}
            val={formik.values.TinNumber}
          />
          <div className="error">
            {formik.touched.TinNumber && formik.errors.TinNumber}
          </div>

          {/* General Image Upload */}
          <h5>License Images</h5>
          <div className="text-center">
            <Dropzone
              onDrop={(acceptedFiles) => handleImageUpload(acceptedFiles, "images")}
            >
              {({ getRootProps, getInputProps }) => (
                <div
                  {...getRootProps()}
                  className="border border-dashed p-4 m-auto"
                  style={{ cursor: "pointer" }}
                >
                  <input {...getInputProps()} />
                  <div className="flex m-auto gap-1">
                    <AiOutlineUpload size={25} />
                    <p>Click or drag files here to upload General Images</p>
                  </div>
                </div>
              )}
            </Dropzone>

            <div className="showimages d-flex flex-wrap gap-3">
              {formik.values.images &&
                formik.values.images.map((img, imgIndex) => (
                  <div className="position-relative" key={imgIndex}>
                    <button
                      type="button"
                      onClick={() => handleImageDelete(img.public_id, "images")}
                      className="btn-close position-absolute"
                      style={{ top: "10px", right: "10px" }}
                    ></button>
                    <img
                      src={img.secure_url}
                      alt={`GeneralImage ${imgIndex + 1}`}
                      width={200}
                      height={200}
                    />
                  </div>
                ))}
            </div>
          </div>

          {/* ID Card Image Upload */}
          <h5>Identification Card Images</h5>
          <div className="text-center">
            <Dropzone
              onDrop={(acceptedFiles) =>
                handleImageUpload(acceptedFiles, "idCardImages")
              }
            >
              {({ getRootProps, getInputProps }) => (
                <div
                  {...getRootProps()}
                  className="border border-dashed p-4 m-auto"
                  style={{ cursor: "pointer" }}
                >
                  <input {...getInputProps()} />
                  <div className="flex m-auto gap-1">
                    <AiOutlineUpload size={25} />
                    <p>Click or drag files here to upload ID Card Images</p>
                  </div>
                </div>
              )}
            </Dropzone>

            <div className="showimages d-flex flex-wrap gap-3">
              {formik.values.idCardImages &&
                formik.values.idCardImages.map((img, imgIndex) => (
                  <div className="position-relative" key={imgIndex}>
                    <button
                      type="button"
                      onClick={() =>
                        handleImageDelete(img.public_id, "idCardImages")
                      }
                      className="btn-close position-absolute"
                      style={{ top: "10px", right: "10px" }}
                    ></button>
                    <img
                      src={img.secure_url}
                      alt={`IDCardImage ${imgIndex + 1}`}
                      width={200}
                      height={200}
                    />
                  </div>
                ))}
            </div>
          </div>

          <button
            className="btn btn-success border-0 rounded-3 my-5"
            type="submit"
            disabled={isLoading}
          >
            {isLoading ? "Uploading..." : "Upload Document"}
          </button>
        </form>
      </div>
    </div>
  );
};

export default AddDocument;
